// This driver simulates running the user's compiled program.
// In a real testing environment, the user's code (e.g., 3917.cpp)
// would be compiled into an executable (e.g., `a.out`).
// This driver would then execute `a.out` with redirected I/O.

std::string run_user_program(const std::string& input_str) {
    std::ofstream input_file("temp_input.txt");
    input_file << input_str;
    input_file.close();

    std::string command = "./a.out < temp_input.txt > temp_output.txt";
    int system_result = system(command.c_str());

    if (system_result != 0) {
        return "Error: Program execution failed.";
    }

    std::ifstream output_file("temp_output.txt");
    std::stringstream ss_output;
    ss_output << output_file.rdbuf();
    output_file.close();

    remove("temp_input.txt");
    remove("temp_output.txt");

    return ss_output.str();
}

